// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

// Structure to represent a node in the tree
typedef struct Node {
    int numChildren;
    int* children;
} Node;

// Function to perform DFS traversal
void dfs(Node* nodes, int* visit, int currentNode, int iteration) {
    if (visit[currentNode] == 0) {
        visit[currentNode] = iteration;
    }
    if (nodes[currentNode].numChildren > 0) {
        int specialChild = nodes[currentNode].children[0];
        dfs(nodes, visit, specialChild, iteration);
        // Update the child index for the next iteration
        nodes[currentNode].children[0] = nodes[currentNode].children[(nodes[currentNode].children[0] % nodes[currentNode].numChildren) + 1];
    }
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        Node* nodes = (Node*)malloc(N * sizeof(Node));
        int* visit = (int*)calloc(N, sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &nodes[i].numChildren);
            nodes[i].children = (int*)malloc(nodes[i].numChildren * sizeof(int));
            for (int j = 0; j < nodes[i].numChildren; j++) {
                scanf("%d", &nodes[i].children[j]);
                nodes[i].children[j]--;
            }
        }
        int iteration = 0;
        bool done = false;
        while (!done) {
            iteration++;
            dfs(nodes, visit, 0, iteration);
            done = true;
            for (int i = 0; i < N; i++) {
                if (visit[i] == 0) {
                    done = false;
                    break;
                }
            }
        }
        for (int i = 0; i < N; i++) {
            printf("%d", visit[i] % MOD);
            if (i < N - 1) printf(" ");
        }
        printf("\n");
        // Free allocated memory
        for (int i = 0; i < N; i++) {
            free(nodes[i].children);
        }
        free(nodes);
        free(visit);
    }
    return 0;
}

