import sys
MOD = 1000000007

class Node:
    def __init__(self):
        self.numChildren = 0
        self.children = []

def dfs(nodes, visit, currentNode, iteration):
    if visit[currentNode] == 0:
        visit[currentNode] = iteration
    if nodes[currentNode].numChildren > 0:
        specialChild = nodes[currentNode].children[0]
        dfs(nodes, visit, specialChild, iteration)
        # Update the child index for the next iteration
        nodes[currentNode].children[0] = nodes[currentNode].children[(nodes[currentNode].children[0] % nodes[currentNode].numChildren) + 1]

def main():
    input = sys.stdin.readline
    T = int(input())
    for _ in range(T):
        N = int(input())
        nodes = [Node() for _ in range(N)]
        visit = [0] * N
        for i in range(N):
            nodes[i].numChildren, *nodes[i].children = map(int, input().split())
            nodes[i].children = [x - 1 for x in nodes[i].children]
        iteration = 0
        done = False
        while not done:
            iteration += 1
            dfs(nodes, visit, 0, iteration)
            done = True
            for i in range(N):
                if visit[i] == 0:
                    done = False
                    break
        print(' '.join(str(x % MOD) for x in visit))
if __name__ == '__main__':
    main()

