// COMPLETE, RUNNABLE JavaScript code
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;

class Node {
    constructor() {
        this.numChildren = 0;
        this.children = [];
    }
}

function dfs(nodes, visit, currentNode, iteration) {
    if (visit[currentNode] === 0) {
        visit[currentNode] = iteration;
    }
    if (nodes[currentNode].numChildren > 0) {
        let specialChild = nodes[currentNode].children[0];
        dfs(nodes, visit, specialChild, iteration);
        // Update the child index for the next iteration
        nodes[currentNode].children[0] = nodes[currentNode].children[(nodes[currentNode].children[0] % nodes[currentNode].numChildren) + 1];
    }
}

function main() {
    let T = parseInt(input[idx++]);
    for (let t = 0; t < T; t++) {
        let N = parseInt(input[idx++]);
        let nodes = Array(N).fill(0).map(() => new Node());
        let visit = Array(N).fill(0);
        for (let i = 0; i < N; i++) {
            let line = input[idx++].split(' ').map(x => parseInt(x));
            nodes[i].numChildren = line[0];
            nodes[i].children = line.slice(1).map(x => x - 1);
        }
        let iteration = 0;
        let done = false;
        while (!done) {
            iteration++;
            dfs(nodes, visit, 0, iteration);
            done = true;
            for (let i = 0; i < N; i++) {
                if (visit[i] === 0) {
                    done = false;
                    break;
                }
            }
        }
        console.log(visit.map(x => x % MOD).join(' '));
    }
}
main();
